        "path": "ark-survival-evolved-trainer/README.md",
        "content": "# ARK: Survival Evolved Trainer\n\nA memory-based trainer for ARK: Survival Evolved (Windows) using ReadProcessMemory/WriteProcessMemory. This project demonstrates process interaction, pattern scanning, and memory manipulation.\n\n**Disclaimer:** For educational purposes only. Modifying game memory violates most EULAs."
    },
    {
        "path": "ark-survival-evolved-trainer/requirements.txt",
        "content": "# .NET dependencies (via NuGet)\n# No external packages required - uses System.Diagnostics and System.Runtime.InteropServices"
    },
    {
        "path": "ark-survival-evolved-trainer/src/MemoryManager.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace ArkTrainer.Core\n{\n    /// <summary>\n    /// Provides low-level memory operations for reading/writing process memory.\n    /// </summary>\n    public class MemoryManager : IDisposable\n    {\n        private readonly IntPtr _processHandle;\n        private readonly int _processId;\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_VM_READ = 0x0010;\n        private const uint PROCESS_VM_WRITE = 0x0020;\n        private const uint PROCESS_VM_OPERATION = 0x0008;\n        private const uint PROCESS_QUERY_INFORMATION = 0x0400;\n\n        /// <summary>\n        /// Opens a handle to the ARK process for memory operations.\n        /// </summary>\n        /// <param name=\"processName\">Name of the target process (without .exe).</param>\n        public MemoryManager(string processName = \"ShooterGame\")\n        {\n            var processes = Process.GetProcessesByName(processName);\n            if (processes.Length == 0)\n                throw new InvalidOperationException($\"Process '{processName}' not found.\");\n\n            _processId = processes[0].Id;\n            _processHandle = OpenProcess(PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION | PROCESS_QUERY_INFORMATION, false, _processId);\n\n            if (_processHandle == IntPtr.Zero)\n                throw new InvalidOperationException($\"Failed to open process handle. Error: {Marshal.GetLastWin32Error()}\");\n        }\n\n        /// <summary>\n        /// Reads bytes from the target process memory.\n        /// </summary>\n        public byte[] ReadBytes(IntPtr address, int size)\n        {\n            byte[] buffer = new byte[size];\n            if (!ReadProcessMemory(_processHandle, address, buffer, size, out _))\n                throw new InvalidOperationException($\"ReadProcessMemory failed at 0x{address.ToInt64():X}\");\n            return buffer;\n        }\n\n        /// <summary>\n        /// Writes bytes to the target process memory.\n        /// </summary>\n        public void WriteBytes(IntPtr address, byte[] data)\n        {\n            if (!WriteProcessMemory(_processHandle, address, data, data.Length, out _))\n                throw new InvalidOperationException($\"WriteProcessMemory failed at 0x{address.ToInt64():X}\");\n        }\n\n        /// <summary>\n        /// Reads a 4-byte float from memory.\n        /// </summary>\n        public float ReadFloat(IntPtr address)\n        {\n            return BitConverter.ToSingle(ReadBytes(address, 4), 0);\n        }\n\n        /// <summary>\n        /// Writes a 4-byte float to memory.\n        /// </summary>\n        public void WriteFloat(IntPtr address, float value)\n        {\n            WriteBytes(address, BitConverter.GetBytes(value));\n        }\n\n        /// <summary>\n        /// Reads a 4-byte integer from memory.\n        /// </summary>\n        public int ReadInt32(IntPtr address)\n        {\n            return BitConverter.ToInt32(ReadBytes(address, 4), 0);\n        }\n\n        /// <summary>\n        /// Writes a 4-byte integer to memory.\n        /// </summary>\n        public void WriteInt32(IntPtr address, int value)\n        {\n            WriteBytes(address, BitConverter.GetBytes(value));\n        }\n\n        public void Dispose()\n        {\n            if (_processHandle != IntPtr.Zero)\n                CloseHandle(_processHandle);\n        }\n    }\n}\n"
    },
    {
        "path": "ark-survival-evolved-trainer/src/PatternScanner.cs",
        "content": "using System;\nusing System.Collections.Generic;\nusing System.Diagnostics;\nusing System.Linq;\nusing System.Runtime.InteropServices;\n\nnamespace ArkTrainer.Core\n{\n    /// <summary>\n    /// Scans process memory for byte patterns (AOB scanning) to find dynamic addresses.\n    /// </summary>\n    public class PatternScanner\n    {\n        private readonly Process _process;\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool VirtualQueryEx(IntPtr hProcess, IntPtr lpAddress, out MEMORY_BASIC_INFORMATION lpBuffer, int dwLength);\n\n        [StructLayout(LayoutKind.Sequential)]\n        private struct MEMORY_BASIC_INFORMATION\n        {\n            public IntPtr BaseAddress;\n            public IntPtr AllocationBase;\n            public uint AllocationProtect;\n            public IntPtr RegionSize;\n            public uint State;\n            public uint Protect;\n            public uint Type;\n        }\n\n        private const uint MEM_COMMIT = 0x1000;\n        private const uint PAGE_READWRITE = 0x04;\n\n        /// <summary>\n        /// Initializes scanner with target process.\n        /// </summary>\n        public PatternScanner(string processName = \"ShooterGame\")\n        {\n            var processes = Process.GetProcessesByName(processName);\n            if (processes.Length == 0)\n                throw new InvalidOperationException($\"Process '{processName}' not found.\");\n            _process = processes[0];\n        }\n\n        /// <summary>\n        /// Scans for a pattern (e.g., \"48 8B 05 ?? ?? ?? ?? 48 85 C0\") in committed RW memory.\n        /// Returns the base address of the first match, or IntPtr.Zero if none found.\n        /// </summary>\n        public IntPtr FindPattern(string pattern, int offset = 0)\n        {\n            byte[] patternBytes = ParsePattern(pattern);\n            bool[] wildcard = pattern.Split(' ').Select(p => p == \"??\").ToArray();\n\n            IntPtr currentAddress = _process.MainModule.BaseAddress;\n            IntPtr endAddress = IntPtr.Add(currentAddress, _process.MainModule.ModuleMemorySize);\n\n            while (currentAddress.ToInt64() < endAddress.ToInt64())\n            {\n                if (!VirtualQueryEx(_process.Handle, currentAddress, out MEMORY_BASIC_INFORMATION mbi, Marshal.SizeOf<MEMORY_BASIC_INFORMATION>()))\n                    break;\n\n                if (mbi.State == MEM_COMMIT && (mbi.Protect & PAGE_READWRITE) != 0)\n                {\n                    byte[] buffer = new byte[(int)mbi.RegionSize];\n                    IntPtr regionEnd = IntPtr.Add(mbi.BaseAddress, (int)mbi.RegionSize);\n\n                    if (ReadProcessMemory(_process.Handle, mbi.BaseAddress, buffer, buffer.Length, out _))\n                    {\n                        int index = IndexOfPattern(buffer, patternBytes, wildcard);\n                        if (index >= 0)\n                        {\n                            IntPtr found = IntPtr.Add(mbi.BaseAddress, index + offset);\n                            return found;\n                        }\n                    }\n                }\n\n                currentAddress = IntPtr.Add(mbi.BaseAddress, (int)mbi.RegionSize);\n            }\n\n            return IntPtr.Zero;\n        }\n\n        private byte[] ParsePattern(string pattern)\n        {\n            string[] parts = pattern.Split(' ');\n            List<byte> bytes = new List<byte>();\n            foreach (string p in parts)\n            {\n                if (p == \"??\")\n                    bytes.Add(0x00); // placeholder, ignored via wildcard\n                else\n                    bytes.Add(Convert.ToByte(p, 16));\n            }\n            return bytes.ToArray();\n        }\n\n        private int IndexOfPattern(byte[] data, byte[] pattern, bool[] wildcard)\n        {\n            for (int i = 0; i <= data.Length - pattern.Length; i++)\n            {\n                bool match = true;\n                for (int j = 0; j < pattern.Length; j++)\n                {\n                    if (!wildcard[j] && data[i + j] != pattern[j])\n                    {\n                        match = false;\n                        break;\n                    }\n                }\n                if (match) return i;\n            }\n            return -1;\n        }\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n    }\n}\n"
    },
